import { mutationGeneric, queryGeneric } from "convex/server";
import { v } from "convex/values";

export const getSessionManagementPageData = queryGeneric({
  args: {
    class_id: v.string(),
  },
  returns: v.union(
    v.null(),
    v.object({
      class_id: v.string(),
      class_name: v.string(),
      sessions: v.array(
        v.object({
          session_id: v.string(),
          location: v.string(),
          date: v.string(),
          time: v.string(),
          quota_defined: v.number(),
          quota_used: v.number(),
          quota_available: v.number(),
          status: v.union(
            v.literal("scheduled"),
            v.literal("completed"),
            v.literal("cancelled")
          ),
        })
      ),
    })
  ),
  handler: async (ctx, args) => {
    const classRecord = await ctx.db
      .query("classes")
      .withIndex("by_class_id", (q) => q.eq("class_id", args.class_id))
      .first();

    if (!classRecord) {
      return null;
    }

    const sessions = await ctx.db
      .query("sessions")
      .withIndex("by_class_id", (q) => q.eq("class_id", args.class_id))
      .collect();

    const sessionRows = sessions.map((s) => ({
      session_id: s.session_id,
      location: s.location,
      date: s.date,
      time: s.time,
      quota_defined: s.quota_defined,
      quota_used: s.quota_used,
      quota_available: Math.max(0, s.quota_defined - s.quota_used),
      status: s.status,
    }));

    return {
      class_id: classRecord.class_id,
      class_name: classRecord.name,
      sessions: sessionRows,
    };
  },
});

export const createSession = mutationGeneric({
  args: {
    class_id: v.string(),
    location: v.string(),
    date: v.string(),
    time: v.string(),
    quota_defined: v.number(),
    admin_username: v.string(),
  },
  returns: v.object({
    session_id: v.string(),
  }),
  handler: async (ctx, args) => {
    const now = Date.now();
